# Liste des produits chimiques dangereux
chemicals = [
    "benzène", "formaldéhyde", "plomb", "mercure", "phtalates", "ammoniac", "acide sulfurique",
    "chlorure de vinyle", "asbeste", "bromure de méthyle", "dioxine", "phtalates", "toluène"
]

# URL de base pour la recherche
base_url = "https://www.google.com/search?q="

# Fonction pour scraper les résultats
def scrape_industrial_uses():
    for chemical in chemicals:
        query = f"utilisation {chemical} applications industrielles"
        url = base_url + query
        headers = {
            "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36"
        }
        try:
            response = requests.get(url, headers=headers)
            soup = BeautifulSoup(response.text, 'html.parser')
            results = soup.find_all('div', class_='BNeawe s3v9rd AP7Wnd')
            for result in results:
                text = result.get_text()
                if chemical.lower() in text.lower():
                    print(f"Produit chimique : {chemical}")
                    print(f"Utilisation trouvée : {text}")
                    print("-" * 50)
        except Exception as e:
            print(f"Erreur lors de la requête pour {chemical} : {e}")

# Exécution du script
if __name__ == "__main__":
    scrape_industrial_uses()
